CREATE TABLE IF NOT EXISTS packages (id INTEGER PRIMARY KEY AUTOINCREMENT, slug TEXT NOT NULL UNIQUE, nameEn TEXT NOT NULL, nameAr TEXT NOT NULL, descriptionEn TEXT, descriptionAr TEXT, price INTEGER NOT NULL DEFAULT 0, currency TEXT NOT NULL DEFAULT 'USD', renewalPrice INTEGER DEFAULT 0, renewalPeriodDays INTEGER DEFAULT 0, renewalDescription TEXT, includesLexai INTEGER NOT NULL DEFAULT 0, includesRecommendations INTEGER NOT NULL DEFAULT 0, includesSupport INTEGER NOT NULL DEFAULT 0, includesPdf INTEGER NOT NULL DEFAULT 0, durationDays INTEGER DEFAULT 0, isLifetime INTEGER NOT NULL DEFAULT 1, isPublished INTEGER NOT NULL DEFAULT 0, displayOrder INTEGER NOT NULL DEFAULT 0, thumbnailUrl TEXT, createdAt TEXT DEFAULT CURRENT_TIMESTAMP NOT NULL, updatedAt TEXT DEFAULT CURRENT_TIMESTAMP NOT NULL);
